// Generated by AI (UnitTest MCP)
import { describe, expect, it } from "vitest";

import { deriveReadiness, ReadinessInput, readinessRows, sessionAgentIdentity } from "./readiness";

const input = (overrides: Partial<ReadinessInput> = {}): ReadinessInput => ({
  memoryConnected: true,
  intentConnected: true,
  memoryServer: { name: "mindleak-mcp", version: "0.1.1+abc123" },
  intentServer: { name: "lodestar-mcp", version: "0.1.1+abc123" },
  graph: { nodes: 12, active_edges: 18 },
  actionableTasks: 0,
  actionableDesigns: 0,
  hasActiveFile: true,
  terminalHealth: "terminal capture active",
  gitHealth: "Git capture active (1 repository)",
  agentId: "vscode-a1b2c3d4",
  ...overrides,
});

describe("deriveReadiness", () => {
  it("reports disconnected planes with a concrete settings action", () => {
    const snapshot = deriveReadiness(
      input({
        intentConnected: false,
        intentError: "lodestar-mcp not found",
      })
    );

    expect(snapshot.state).toBe("disconnected");
    expect(snapshot.detail).toContain("lodestar-mcp not found");
    expect(snapshot.action).toEqual({
      label: "Open MindLeak settings",
      command: "workbench.action.openSettings",
      arguments: ["@ext:monk-eee.mindleak"],
    });
  });

  it("guides an empty graph to the first ingest without requiring a model", () => {
    const withEditor = deriveReadiness(input({ graph: { nodes: 0, active_edges: 0 } }));
    const withoutEditor = deriveReadiness(
      input({ graph: { nodes: 0, active_edges: 0 }, hasActiveFile: false })
    );

    expect(withEditor.state).toBe("ready_empty");
    expect(withEditor.action.command).toBe("mindleak.ingestActiveFile");
    expect(withoutEditor.action.command).toBe("workbench.action.files.openFile");
  });

  it("surfaces coordination before optional sensor degradation", () => {
    const tasks = deriveReadiness(
      input({ actionableTasks: 2, terminalHealth: "terminal capture degraded: no shell" })
    );
    const designs = deriveReadiness(input({ actionableTasks: 2, actionableDesigns: 1 }));

    expect(tasks.state).toBe("coordinating");
    expect(tasks.action.command).toBe("mindleak.boardView.focus");
    expect(designs.action.command).toBe("mindleak.designView.focus");
  });

  it("names optional degradation without presenting the core as offline", () => {
    const snapshot = deriveReadiness(
      input({
        terminalHealth: "terminal capture disabled",
        gitHealth: "Git capture degraded: built-in Git extension unavailable",
      })
    );

    expect(snapshot.state).toBe("degraded_optional");
    expect(snapshot.title).toContain("Core ready");
    expect(snapshot.degradedCapabilities).toHaveLength(2);
    expect(snapshot.action.command).toBe("mindleak.telemetryView.focus");
  });

  it("reports an observing graph with exact server builds and agent identity", () => {
    const snapshot = deriveReadiness(input());

    expect(snapshot.state).toBe("observing");
    expect(snapshot.detail).toContain("12 node(s)");
    expect(snapshot.memory).toBe("mindleak-mcp 0.1.1+abc123");
    expect(snapshot.intent).toBe("lodestar-mcp 0.1.1+abc123");
    expect(snapshot.agent).toBe("vscode-a1b2c3d4");
  });
});

describe("readinessRows", () => {
  it("renders the primary action, both planes, identity, and optional issues", () => {
    const rows = readinessRows(
      deriveReadiness(input({ terminalHealth: "terminal capture disabled" }))
    );

    expect(rows.map((row) => row.id)).toEqual(["state", "memory", "intent", "agent", "optional-0"]);
    expect(rows[0].action?.command).toBe("mindleak.telemetryView.focus");
    expect(rows[1].description).toContain("0.1.1+abc123");
    expect(rows[4].icon).toBe("warning");
  });
});

describe("sessionAgentIdentity", () => {
  it("derives one bounded fixed identity from the configured base and activation nonce", () => {
    expect(sessionAgentIdentity(" vscode ", "A1B2-C3D4-E5F6")).toBe(
      "session:v1:vscode:16308361808fdf63e94ea02e7c0c02c2"
    );
    expect(sessionAgentIdentity("", "not-valid!suffix")).toBe(
      "session:v1:vscode:089203652151b3043473cabe6ee03f86"
    );
    expect(sessionAgentIdentity("agent", "---")).toBe(
      "session:v1:agent:cb3f91d54eee30e53e35b2b99905f70f"
    );
  });
});
